from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine
from collections import defaultdict

def aggregate_search_results(
    search_results: List[SearchResult],
    group_by_field: str,
    aggregation_funcs: Optional[Dict[str, Callable]] = None
) -> Dict[str, Dict[str, Any]]:
    """Aggregate search results by a metadata field with optional statistics.

    Args:
        search_results: List of SearchResult objects to aggregate
        group_by_field: Metadata field name to group by
        aggregation_funcs: Optional dictionary mapping field_name to aggregation function.
            Example: {"score": max, "count": len}
            If None, defaults to count and average score per group

    Returns:
        Dictionary mapping group_value to aggregated statistics
        Example: {"tech": {"count": 5, "avg_score": 0.85, "max_score": 0.95}}
    """
    # Initialize grouping structure
    groups = defaultdict(list)

    # Group results by the specified metadata field
    for result in search_results:
        # Extract metadata field value for grouping
        field_value = result.metadata.get(group_by_field)

        # Handle missing field values by assigning to 'unknown' group
        if field_value is None:
            group_key = 'unknown'
        else:
            group_key = str(field_value)

        groups[group_key].append(result)

    # Define default aggregation functions if none provided
    if aggregation_funcs is None:
        aggregation_funcs = {
            'count': len,
            'avg_score': lambda group: sum(r.score for r in group) / len(group) if group else 0,
            'max_score': lambda group: max(r.score for r in group) if group else 0,
            'min_score': lambda group: min(r.score for r in group) if group else 0
        }

    # Calculate aggregated statistics for each group
    aggregated_results = {}

    for group_key, group_results in groups.items():
        group_stats = {}

        for stat_name, agg_func in aggregation_funcs.items():
            try:
                # Apply aggregation function to the appropriate data
                if stat_name == 'count':
                    # Count is a special case - it's the length of the group
                    group_stats[stat_name] = agg_func(group_results)
                else:
                    # For other stats, extract the field values first
                    field_values = [getattr(result, stat_name, None) for result in group_results]
                    # Filter out None values before aggregation
                    valid_values = [val for val in field_values if val is not None]
                    if valid_values:
                        group_stats[stat_name] = agg_func(valid_values)
                    else:
                        group_stats[stat_name] = 0  # Default value for empty groups
            except Exception as e:
                # Handle cases where aggregation fails (e.g., type errors)
                group_stats[stat_name] = f"Error: {str(e)}"

        aggregated_results[group_key] = group_stats

    return aggregated_results

