from typing import List, Dict, Any
from leann.api import PassageManager, LeannSearcher
from pathlib import Path
import json
from collections import Counter, defaultdict

def get_index_statistics(
    index_path: str
) -> Dict[str, Any]:
    """Get comprehensive statistics about a LEANN index.

Args:
    index_path: Path to the LEANN index file

Returns:
    Dictionary containing:
    {
        "total_passages": total number of passages,
        "metadata_fields": list of unique metadata field names,
        "field_value_counts": dictionary of field value counts
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""
    # Initialize PassageManager to load index metadata and passages
    try:
        passage_manager = PassageManager([index_path])
    except FileNotFoundError as e:
        raise FileNotFoundError(f"Index metadata file not found for path: {index_path}") from e

    # Calculate total number of passages using length of passage manager
    total_passages = len(passage_manager)

    # Extract metadata from all passages and collect field names
    metadata_fields = set()
    field_value_counts = defaultdict(Counter)

    for passage_id in passage_manager:
        try:
            passage_data = passage_manager.get_passage(passage_id)
            passage_metadata = passage_data.get("metadata", {})

            # Collect field names
            for field_name in passage_metadata.keys():
                metadata_fields.add(field_name)

                # Count field values
                field_value = passage_metadata[field_name]
                if isinstance(field_value, (list, tuple)):
                    for value in field_value:
                        field_value_counts[field_name][value] += 1
                else:
                    field_value_counts[field_name][field_value] += 1

        except KeyError:
            # Skip passages that cannot be retrieved
            continue

    # Convert to list and sort field names
    sorted_metadata_fields = sorted(list(metadata_fields))

    # Prepare result dictionary
    result = {
        "total_passages": total_passages,
        "metadata_fields": sorted_metadata_fields,
        "field_value_counts": {field: dict(counts) for field, counts in field_value_counts.items()}
    }

    return result

def analyze_index_coverage(index_path: str, required_fields: List[str]) -> Dict[str, Any]:
    """Analyze how well an index covers required metadata fields.

Args:
    index_path: Path to the LEANN index file
    required_fields: List of metadata field names that should be present

Returns:
    Dictionary containing:
    {
        "coverage_percentage": percentage of passages that have all required fields,
        "field_coverage": dictionary mapping field name to coverage percentage,
        "missing_fields": list of required fields not found in any passage
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""
    # Initialize PassageManager to load index metadata and passages
    try:
        passage_manager = PassageManager([index_path])
    except FileNotFoundError as e:
        raise FileNotFoundError(f"Index metadata file not found for path: {index_path}") from e

    # Track coverage for each required field
    field_coverage = {field: 0 for field in required_fields}
    total_passages = len(passage_manager)
    full_coverage_count = 0
    missing_fields = set(required_fields)

    for passage_id in passage_manager:
        try:
            passage_data = passage_manager.get_passage(passage_id)
            passage_metadata = passage_data.get("metadata", {})

            # Check each required field
            has_all_fields = True
            for field in required_fields:
                if field in passage_metadata:
                    field_coverage[field] += 1
                    if field in missing_fields:
                        missing_fields.remove(field)
                else:
                    has_all_fields = False

            if has_all_fields:
                full_coverage_count += 1

        except KeyError:
            # Skip passages that cannot be retrieved
            continue

    # Calculate percentages
    coverage_percentage = (full_coverage_count / total_passages) * 100 if total_passages > 0 else 0
    field_coverage_percent = {field: (count / total_passages) * 100 for field, count in field_coverage.items()}

    # Prepare result dictionary
    result = {
        "coverage_percentage": round(coverage_percentage, 2),
        "field_coverage": {field: round(percent, 2) for field, percent in field_coverage_percent.items()},
        "missing_fields": sorted(list(missing_fields))
    }

    return result
